(function () {
  const assetVersion = "20260512-hybrid-assets";
  const crewImages = {
  "portrait-00": "data:image/jpeg;base64,",
  "portrait-01": "data:image/jpeg;base64,",
  "portrait-02": "data:image/jpeg;base64,",
  "portrait-03": "data:image/jpeg;base64,",
  "portrait-04": "data:image/jpeg;base64,",
  "portrait-05": "data:image/jpeg;base64,",
  "portrait-06": "data:image/jpeg;base64,",
  "portrait-07": "data:image/jpeg;base64,",
  "portrait-08": "data:image/jpeg;base64,",
  "portrait-09": "data:image/jpeg;base64,",
  "portrait-10": "data:image/jpeg;base64,",
  "portrait-11": "data:image/jpeg;base64,",
  "portrait-12": "data:image/jpeg;base64,",
  "portrait-13": "data:image/jpeg;base64,",
  "portrait-14": "data:image/jpeg;base64,",
  "portrait-15": "data:image/jpeg;base64,"
};
  const shipImages = {
  "aster-5": "data:image/jpeg;base64,",
  "atlas-16": "data:image/jpeg;base64,",
  "helios-12": "data:image/jpeg;base64,",
  "orion-9": "data:image/jpeg;base64,",
  "vega-7": "data:image/jpeg;base64,"
};
  const enemyImages = {
  "drone": "data:image/jpeg;base64,",
  "probe": "data:image/jpeg;base64,",
  "raider": "data:image/jpeg;base64,",
  "skiff": "data:image/jpeg;base64,"
};
  const sceneImages = {
  "approach": "data:image/jpeg;base64,",
  "encounter": "data:image/jpeg;base64,",
  "objective": "data:image/jpeg;base64,",
  "ready": "data:image/jpeg;base64,",
  "return": "data:image/jpeg;base64,",
  "scan": "data:image/jpeg;base64,"
};

  function frame(className, src, fallback, extra = "") {
    if (!src) return fallback;
    return '<div class="ai-asset-frame ' + className + '" data-asset-version="' + assetVersion + '">' +
      '<img src="' + src + '" alt="" loading="lazy" onerror="this.closest(\'.ai-asset-frame\')?.classList.add(\'is-missing\')">' +
      extra +
      '<div class="ai-fallback">' + fallback + '</div>' +
    '</div>';
  }

  function crewIndex(member) {
    const seed = String(member?.id || member?.name || "crew");
    let hash = 0;
    for (let i = 0; i < seed.length; i += 1) hash = (hash * 31 + seed.charCodeAt(i)) >>> 0;
    return String(hash % 16).padStart(2, "0");
  }

  function rankMarkup(member, department) {
    const rank = member?.rankCode || member?.rank?.code || member?.rank || "CDT";
    const level = Number(member?.level || 0);
    const pips = Array.from({ length: Math.min(5, Math.max(1, level + 1)) }, (_, i) => '<span class="' + (i <= level ? 'is-on' : '') + '"></span>').join('');
    return '<span class="ai-rank-badge dept-' + (department?.id || member?.department || 'command') + '">' + rank + '</span><span class="ai-rank-pips">' + pips + '</span>';
  }

  function normalizeShipId(shipOrClass, shipClass) {
    return shipClass?.id || shipOrClass?.classId || shipOrClass?.id || "aster-5";
  }

  function normalizeScenePhase(phase) {
    if (!phase) return "ready";
    if (phase === "travel") return "approach";
    return sceneImages[phase] ? phase : "ready";
  }

  window.LunarAssets = {
    assetVersion,
    crewPortrait(member, department, fallback) {
      return frame('crew-portrait', crewImages[crewIndex(member)], fallback, rankMarkup(member, department));
    },
    shipVisual(shipOrClass, shipClass, fallback) {
      return frame('ship-visual', shipImages[normalizeShipId(shipOrClass, shipClass)], fallback);
    },
    enemyVisual(enemy, fallback) {
      return frame('enemy-visual', enemyImages[enemy?.kind || enemy?.id || 'drone'], fallback);
    },
    sceneArt(phase, fallback) {
      const key = normalizeScenePhase(phase);
      const src = sceneImages[key];
      if (!src) return fallback;
      return '<div class="mission-scene-image-wrap" data-asset-version="' + assetVersion + '"><img class="mission-scene-image" src="' + src + '" alt="" loading="eager" onerror="this.closest(\'.mission-scene-image-wrap\')?.classList.add(\'is-missing\')">' + fallback + '</div>';
    }
  };
})();
